227→    _runHook(onUpdateHook)
228→        .then(() => {
229→            if (window.MathJax != null) {
230→                /* Anki-Android adds mathjax-needs-to-render" as a class to the card when
231→                   it detects both \( and \) or \[ and \].
232→
233→                   This does not control *loading* MathJax, but rather controls whether or not MathJax
234→                   renders content.  We hide all the content until MathJax renders, because otherwise
235→                   the content loads, and has to reflow after MathJax renders, and it's unsightly.
236→                   However, if we hide all the content every time, folks don't like the repainting after
237→                   every question or answer.  This is a middle-ground, where there is no repainting due to
238→                   MathJax on non-MathJax cards, and on MathJax cards, there is a small flicker, but there's
239→                   no reflowing because the content only shows after MathJax has rendered. */
240→
241→                if (card.classList.contains("mathjax-needs-to-render")) {
242→                    return MathJax.startup.promise
243→                        .then(() => MathJax.typesetPromise([card]))
244→                        .then(() => card.classList.remove("mathjax-needs-to-render"));
245→                }
246→            }
247→        })
248→        .then(() => card.classList.add("mathjax-rendered"))
249→        .then(_runHook(onShownHook));
250→};
